content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以幫我點一杯紅茶嗎？",
      "pinyin": "Máfan nǐ, kěyǐ bāng wǒ diǎn yī bēi hóngchá ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 bang1 wo3 dian3 yi1 bei1 hong2cha2 ma0?",
      "translation_en": "Excuse me, could you help me order a black tea?",
      "translation_ko": "실례합니다, 홍차 한 잔 주문하는 것을 도와주시겠어요?"
    },
    {
      "text": "不好意思，可以給我一個袋子嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "bu4 hao3 yi4si, ke3yi3 gei3 wo3 yi1 ge4 dai4zi ma0?",
      "translation_en": "Excuse me, could you give me a bag?",
      "translation_ko": "죄송합니다, 봉투 하나를 주시겠어요?"
    },
    {
      "text": "請問，可以幫我加珍珠嗎？",
      "pinyin": "Qǐngwèn, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "qing3wen4, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "실례합니다, 타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "我想要一杯綠茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4cha2, ban4 tang2, ke3yi3 ma0?",
      "translation_en": "I would like a green tea, half sugar, okay?",
      "translation_ko": "녹차 한 잔, 반당으로 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我中杯的豆漿嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ zhōng bēi de dòujiāng ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 gei3 wo3 zhong1 bei1 de dou4jiang1 ma0?",
      "translation_en": "Excuse me, could you give me a medium soy milk?",
      "translation_ko": "실례합니다, 중간 컵의 두유를 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不懂。",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma? Wǒ tīng bù dǒng.",
      "pinyin_numeric": "bu4 hao3 yi4si, ke3yi3 zai4 shuo1 yi1 ci4 ma0? Wo3 ting1 bu4 dong3.",
      "translation_en": "Excuse me, could you say it again? I don't understand.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 제가 이해하지 못했어요."
    },
    {
      "text": "請問，可以慢一點說嗎？",
      "pinyin": "Qǐngwèn, kěyǐ màn yī diǎn shuō ma?",
      "pinyin_numeric": "qing3wen4, ke3yi3 man4 yi1 dian3 shuo1 ma0?",
      "translation_en": "Excuse me, could you speak a little slower?",
      "translation_ko": "실례합니다, 조금 천천히 말씀해 주시겠어요?"
    },
    {
      "text": "我想要一杯冰的紅茶，少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi bīng de hóngchá, shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 bing1 de hong2cha2, shao3 bing1, ke3yi3 ma0?",
      "translation_en": "I would like an iced black tea, less ice, okay?",
      "translation_ko": "얼음 홍차 한 잔, 얼음 적게로 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以幫我外帶嗎？",
      "pinyin": "Máfan nǐ, kěyǐ bāng wǒ wàidài ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 bang1 wo3 wai4dai4 ma0?",
      "translation_en": "Excuse me, could you help me with takeout?",
      "translation_ko": "실례합니다, 포장해 주시겠어요?"
    }
  ]
}
